// NewPolicyQuotaController creates a new PolicyQuotaController.
func NewPolicyQuotaController(
	log logrus.FieldLogger,
	maxPerNamespace int,
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:                   log.WithField(logfields.LogSubsys, "policy-quota"),
		maxPerNamespace:       maxPerNamespace,
		namespacePolicyCnt:    make(map[string]int),
		ciliumNetworkPolicies: ciliumNetworkPolicies,
	}
}

// Run implements the controller loop that watches CiliumNetworkPolicy resources
// and enforces per-namespace quota limits.
func (pqc *PolicyQuotaController) Run(ctx context.Context) error {
	pqc.log.Info("Starting PolicyQuotaController")

	events := pqc.ciliumNetworkPolicies.Events(ctx)

	for {
		select {
		case <-ctx.Done():
			pqc.log.Info("PolicyQuotaController context cancelled")
			return ctx.Err()
		case event, ok := <-events:
			if !ok {
				pqc.log.Info("PolicyQuotaController events channel closed")
				return nil
			}

			if event.Kind == resource.Sync {
				pqc.log.Debug("PolicyQuotaController synced with API server")
				event.Done(nil)
				continue
			}

			var err error
			switch event.Kind {
			case resource.Upsert:
				err = pqc.handleUpsert(event.Object)
			case resource.Delete:
				err = pqc.handleDelete(event.Object)
			}

			event.Done(err)
		}
	}
}

// handleUpsert processes a CiliumNetworkPolicy upsert event.
func (pqc *PolicyQuotaController) handleUpsert(cnp *cilium_v2.CiliumNetworkPolicy) error {
	namespace := cnp.GetNamespace()
	if namespace == "" {
		// Skip cluster-wide policies
		return nil
	}

	pqc.mu.Lock()
	defer pqc.mu.Unlock()

	pqc.namespacePolicyCnt[namespace]++
	pqc.log.WithField("namespace", namespace).
		WithField("count", pqc.namespacePolicyCnt[namespace]).
		Debug("CiliumNetworkPolicy upserted")

	return nil
}

// handleDelete processes a CiliumNetworkPolicy delete event.
func (pqc *PolicyQuotaController) handleDelete(cnp *cilium_v2.CiliumNetworkPolicy) error {
	namespace := cnp.GetNamespace()
	if namespace == "" {
		// Skip cluster-wide policies
		return nil
	}

	pqc.mu.Lock()
	defer pqc.mu.Unlock()

	if count, exists := pqc.namespacePolicyCnt[namespace]; exists && count > 0 {
		pqc.namespacePolicyCnt[namespace]--
	}
	pqc.log.WithField("namespace", namespace).
		WithField("count", pqc.namespacePolicyCnt[namespace]).
		Debug("CiliumNetworkPolicy deleted")

	return nil
}

// CheckQuota checks if a namespace has exceeded its policy quota.
// Returns an error if the quota would be exceeded.
func (pqc *PolicyQuotaController) CheckQuota(namespace string) error {
	if namespace == "" {
		// No quota check for cluster-wide policies
		return nil
	}

	pqc.mu.RLock()
	count := pqc.namespacePolicyCnt[namespace]
	pqc.mu.RUnlock()

	if count >= pqc.maxPerNamespace {
		return fmt.Errorf(
			"policy quota exceeded for namespace %q: current=%d, max=%d",
			namespace,
			count,
			pqc.maxPerNamespace,
		)
	}

	return nil
}

// GetNamespacePolicyCount returns the current policy count for a namespace.
func (pqc *PolicyQuotaController) GetNamespacePolicyCount(namespace string) int {
	pqc.mu.RLock()
	defer pqc.mu.RUnlock()

	return pqc.namespacePolicyCnt[namespace]
}

// ResetNamespace clears the policy count for a namespace.
func (pqc *PolicyQuotaController) ResetNamespace(namespace string) {
	pqc.mu.Lock()
	defer pqc.mu.Unlock()

	delete(pqc.namespacePolicyCnt, namespace)
}

